#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) { return (*(int*)a - *(int*)b); }
int main() {
    int T, N, M;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &M);
        int houses[N], taps[M];
        for (int i = 0; i < N; i++) scanf("%d", &houses[i]);
        for (int i = 0; i < M; i++) scanf("%d", &taps[i]);
        qsort(houses, N, sizeof(int), compare);
        qsort(taps, M, sizeof(int), compare);
        long long cost = 0;
        for (int i = 0; i < N; i++) {
            cost += abs(houses[i] - taps[i % M]);
        }
        printf("%lld\n", cost);
    }
    return 0;
}

