    if (i === 0) {
        T = parseInt(line);
    } else {
        input.push(line.split(' ').map(num => parseInt(num)));
    }
    i++;
    if (i === T * 2 + 1) {
        for (let j = 0; j < T; j++) {
            let N = input[j * 2][0];
            let M = input[j * 2][1];
            let houses = input.slice(j * 2 + 1, j * 2 + N + 1);
            let taps = input.slice(j * 2 + N + 1, j * 2 + N + M + 1);
